<?php
declare(strict_types=1);
namespace App\Core\System;
use PDO;
final readonly class HealthService{public function __construct(private HealthRepository $healthRepository,private LogRepository $logRepository,private PDO $pdo){} public function listHealthChecks(int $tenantId): array {return $this->healthRepository->listDefinitionsWithLastResult($tenantId, 100);} public function runHealthCheck(int $id,?int $tenantId,?int $userId,?string $ipAddress,?string $userAgent): string {$def=$this->healthRepository->findDefinitionById($id); if($def===null){return 'Health check no encontrado.';} $start=microtime(true); $status='error'; $message='No se pudo ejecutar el health check.'; try{$type=strtolower(trim((string)($def['check_type']??''))); if($type==='system'){$this->pdo->query('SELECT 1'); $status='info'; $message='Health check ejecutado correctamente.';}}catch(\Throwable){} $ms=(int)round((microtime(true)-$start)*1000); $this->logRepository->insert([':tenant_id'=>$tenantId,':user_id'=>$userId,':level'=>$status==='info'?'info':'error',':module_code'=>(string)($def['module_code']??'system'),':channel'=>'system.health',':message'=>$message,':context_json'=>json_encode(['health_check_id'=>$id,'status'=>$status,'duration_ms'=>$ms], JSON_UNESCAPED_UNICODE),':ip_address'=>$ipAddress,':user_agent'=>$userAgent]); return $message;}}
